module top_module(
                                input  wire clock,
                                input  wire pre_clear,
                                output wire reset_out
                              );parameter PIPE_DEPTH = 4;

    // Declare pipeline registers.
    reg [PIPE_DEPTH - 1 : 0]  reset_pipeline;
    integer                   i;

    always @(posedge clock or negedge pre_clear)
    begin

        if (pre_clear == 1'b0)
        begin
            reset_pipeline <= 0;
        end

        else
        begin
           for (i=0; i< PIPE_DEPTH; i = i + 1)
           begin
               if (i==0)
                   reset_pipeline[i] <= 1'b1;
               else
                   reset_pipeline[i] <= reset_pipeline[i-1];
           end
        end // if-else

    end // always

    assign reset_out = reset_pipeline[PIPE_DEPTH-1];

endmodule
